#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define MAXN 1000000
#define MAXT 50
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int T, N, i, j, k, D, xi, yi, xj, yj, dist;
    int points[MAXN][2];
    int distances[MAXN * MAXN];
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (i = 0; i < N; i++) {
            scanf("%d %d", &xi, &yi);
            points[i][0] = xi;
            points[i][1] = yi;
        }
        k = 0;
        for (i = 0; i < N; i++) {
            for (j = i + 1; j < N; j++) {
                xi = points[i][0];
                yi = points[i][1];
                xj = points[j][0];
                yj = points[j][1];
                dist = abs(xi - xj) + abs(yi - yj);
                distances[k++] = dist;
            }
        }
        qsort(distances, k, sizeof(int), compare);
        D = distances[k - 1];
        while (1) {
            int visited[MAXN];
            for (i = 0; i < N; i++) {
                visited[i] = 0;
            }
            visited[0] = 1;
            int count = 1;
            for (i = 0; i < N; i++) {
                if (visited[i]) {
                    for (j = 0; j < N; j++) {
                        if (!visited[j]) {
                            xi = points[i][0];
                            yi = points[i][1];
                            xj = points[j][0];
                            yj = points[j][1];
                            dist = abs(xi - xj) + abs(yi - yj);
                            if (dist >= D) {
                                visited[j] = 1;
                                count++;
                            }
                        }
                    }
                }
            }
            if (count == N) {
                printf("%d\n", D);
                break;
            }
            D--;
        }
    }
    return 0;
}

