import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[][] points = new int[N][2];
            for (int i = 0; i < N; i++) {
                points[i][0] = sc.nextInt();
                points[i][1] = sc.nextInt();
            }
            int[] distances = new int[N * (N - 1) / 2];
            int k = 0;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    int xi = points[i][0];
                    int yi = points[i][1];
                    int xj = points[j][0];
                    int yj = points[j][1];
                    int dist = Math.abs(xi - xj) + Math.abs(yi - yj);
                    distances[k++] = dist;
                }
            }
            Arrays.sort(distances);
            int D = distances[distances.length - 1];
            while (true) {
                boolean[] visited = new boolean[N];
                visited[0] = true;
                int count = 1;
                for (int i = 0; i < N; i++) {
                    if (visited[i]) {
                        for (int j = 0; j < N; j++) {
                            if (!visited[j]) {
                                int xi = points[i][0];
                                int yi = points[i][1];
                                int xj = points[j][0];
                                int yj = points[j][1];
                                int dist = Math.abs(xi - xj) + Math.abs(yi - yj);
                                if (dist >= D) {
                                    visited[j] = true;
                                    count++;
                                }
                            }
                        }
                    }
                }
                if (count == N) {
                    System.out.println(D);
                    break;
                }
                D--;
            }
        }
    }
}

